/**
 * Minimal OpenAI-compatible streaming LLM client.
 * Uses raw `fetch` + `ReadableStream` — no external dependencies.
 *
 * Reads LLM_API_KEY, LLM_MODEL, LLM_BASE_URL from environment.
 * LLM_API_KEY is never logged or included in SSE responses.
 */

import { createLogger } from './logger.js';

const logger = createLogger('llm-client');

const DEFAULT_BASE_URL = 'https://api.openai.com/v1';
const DEFAULT_MODEL = 'gpt-4o-mini';
const TIMEOUT_MS = 30_000;

export class LlmClient {
	private readonly apiKey: string;
	private readonly model: string;
	private readonly baseUrl: string;
	private readonly timeoutMs: number;

	constructor(opts?: { baseUrl?: string; model?: string; apiKey?: string; timeoutMs?: number }) {
		this.apiKey = opts?.apiKey ?? process.env.LLM_API_KEY ?? '';
		this.model = opts?.model ?? process.env.LLM_MODEL ?? DEFAULT_MODEL;
		this.baseUrl = (opts?.baseUrl ?? process.env.LLM_BASE_URL ?? DEFAULT_BASE_URL).replace(/\/+$/, '');
		this.timeoutMs = opts?.timeoutMs ?? TIMEOUT_MS;
	}

	/**
	 * Stream a chat-completion and yield content deltas as strings.
	 * Parses SSE `data:` lines from the OpenAI-compatible response.
	 *
	 * Throws on non-OK HTTP status, timeout, or stream errors.
	 */
	async *chatCompletionStream(systemPrompt: string, userMessage: string): AsyncGenerator<string> {
		const url = `${this.baseUrl}/chat/completions`;

		logger.info('Request', {
			url,
			model: this.model,
			systemPromptLength: systemPrompt.length,
			userMessageLength: userMessageLength
			// apiKey intentionally omitted
		});

		const controller = new AbortController();
		const timer = setTimeout(() => controller.abort(), this.timeoutMs);

		let response: Response;
		try {
			response = await fetch(url, {
				method: 'POST',
				headers: {
					'Content-Type': 'application/json',
					Authorization: `Bearer ${this.apiKey}`
				},
				body: JSON.stringify({
					model: this.model,
					stream: true,
					messages: [
						{ role: 'system', content: systemPrompt },
						{ role: 'user', content: userMessage }
					]
				}),
				signal: controller.signal
			});
		} catch (err: any) {
			clearTimeout(timer);
			if (err.name === 'AbortError') {
				throw new Error(`LLM request timed out after ${this.timeoutMs}ms`);
			}
			throw new Error(`LLM connection failed: ${err.message}`);
		}

		clearTimeout(timer);

		if (!response.ok) {
			const body = await response.text().catch(() => '<unreadable>');
			throw new Error(`LLM API returned ${response.status}: ${body.slice(0, 500)}`);
		}

		// ── Parse SSE stream ────────────────────────────────────────────
		const reader = response.body!.getReader();
		const decoder = new TextDecoder();
		let buffer = '';

		try {
			while (true) {
				const { done, value } = await reader.read();
				if (done) break;

				buffer += decoder.decode(value, { stream: true });

				// Split on newlines, process complete SSE lines
				const lines = buffer.split('\n');
				buffer = lines.pop() ?? ''; // keep incomplete line in buffer

				for (const line of lines) {
					const trimmed = line.trim();
					if (!trimmed || trimmed.startsWith(':')) continue; // skip empty / comments

					if (trimmed === 'data: [DONE]') return;

					if (trimmed.startsWith('data: ')) {
						const jsonStr = trimmed.slice(6);
						try {
							const parsed = JSON.parse(jsonStr);
							const delta = parsed.choices?.[0]?.delta?.content;
							if (delta) yield delta;
						} catch {
							// Malformed JSON chunk — skip silently (stream continues)
						}
					}
				}
			}
		} finally {
			reader.releaseLock();
		}
	}
}

/**
 * Compare service — streams LLM comparison of decomposed result vs original requirements.
 *
 * Takes source markdown + confirmed modules/tasks, asks the LLM to compare
 * and suggest improvements. Output is advisory plain text (not structured JSON).
 *
 * Uses SSE events: suggestion (text chunks), done, error.
 */

import { LlmClient } from './llm-client.js';
import { createLogger } from './logger.js';
import type { ConfirmModule } from '$lib/schemas/confirm.js';
import type {
	CompareEvent,
	CompareSuggestionEvent,
	CompareErrorEvent,
	CompareDoneEvent
} from '$lib/schemas/confirm.js';

const logger = createLogger('compare-service');

// ── System prompt ────────────────────────────────────────────────────────────

const SYSTEM_PROMPT = `你是一个专业的项目管理助手。你的任务是对比原始需求文档和拆解结果，给出改进建议。

## 工作方式

1. 仔细阅读原始需求文档
2. 对比已拆解的模块和任务
3. 指出可能遗漏的需求点
4. 建议模块或任务的优化方向
5. 标注优先级较高的建议

## 输出要求

- 用简洁的中文输出分析结果
- 每个建议单独一段，标注类型（遗漏/优化/拆分建议）
- 最后给出一个简短的总结评分（覆盖度 0-100%）
- 不要输出 JSON 或结构化格式，直接输出纯文本`;

// ── Public API ───────────────────────────────────────────────────────────────

/**
 * Stream LLM comparison of source markdown vs confirmed modules.
 *
 * Yields CompareEvent objects:
 * - `{ type: 'suggestion', content }` — text chunk from LLM
 * - `{ type: 'error', stage, message }` — error during streaming
 * - `{ type: 'done' }` — stream complete
 */
export async function* streamCompare(
	sourceMd: string,
	confirmedModules: ConfirmModule[],
	client?: LlmClient
): AsyncGenerator<CompareEvent> {
	const llm = client ?? new LlmClient();

	// Build a structured text representation of the confirmed modules
	const modulesText = confirmedModules
		.map((mod, idx) => {
			const tasksText = mod.tasks.map((t, tIdx) => `    ${tIdx + 1}. ${t.title}${t.description ? ` - ${t.description}` : ''}`).join('\n');
			return `模块 ${idx + 1}: ${mod.name}${mod.description ? `\n  描述: ${mod.description}` : ''}\n  任务:\n${tasksText}`;
		})
		.join('\n\n');

	const userMessage = `## 原始需求文档

${sourceMd}

## 拆解结果

${modulesText}

请对比以上内容，给出改进建议。`;

	logger.info('Starting comparison', {
		sourceMdLength: sourceMd.length,
		moduleCount: confirmedModules.length,
		taskCount: confirmedModules.reduce((sum, m) => sum + m.tasks.length, 0)
		// apiKey intentionally omitted
	});

	try {
		for await (const chunk of llm.chatCompletionStream(SYSTEM_PROMPT, userMessage)) {
			const event: CompareSuggestionEvent = {
				type: 'suggestion',
				content: chunk
			};
			yield event;
		}

		const doneEvent: CompareDoneEvent = { type: 'done' };
		yield doneEvent;
		logger.info('Comparison complete');
	} catch (err: any) {
		const stage: 'connecting' | 'streaming' = 'connecting';
		const errorEvent: CompareErrorEvent = {
			type: 'error',
			stage,
			message: err.message
		};
		yield errorEvent;
		logger.warn('Stream error', { error: err.message });
	}
}

/**
 * Confirm service — atomically writes confirmed modules/tasks to DB
 * and activates the milestone (draft → in-progress).
 *
 * Pre-generates all IDs, then uses a synchronous drizzle transaction
 * (required by better-sqlite3) for atomic writes.
 */

import { eq } from 'drizzle-orm';
import type { BetterSQLite3Database } from 'drizzle-orm/better-sqlite3';
import { modules, tasks, milestones } from '$lib/db/schema.js';
import type { ConfirmModule } from '$lib/schemas/confirm.js';
import { createLogger } from './logger.js';

const logger = createLogger('confirm-service');

// ── Types ────────────────────────────────────────────────────────────────────

export interface ConfirmResultModule {
	id: string;
	milestoneId: string;
	name: string;
	description: string | null;
	status: string;
	sortOrder: number;
	tasks: ConfirmResultTask[];
}

export interface ConfirmResultTask {
	id: string;
	shortId: number;
	moduleId: string;
	title: string;
	description: string | null;
	status: string;
}

export interface ConfirmError {
	code: 'not_found' | 'bad_request';
	message: string;
}

// ── Public API ───────────────────────────────────────────────────────────────

/**
 * Confirm a milestone's decomposed modules and tasks.
 *
 * - Validates milestone exists, is 'draft', and has sourceMd
 * - Pre-generates all IDs (async phase)
 * - Inserts all modules and tasks in a synchronous transaction
 * - Updates milestone status to 'in-progress'
 * - Returns the created structure with all generated IDs
 */
export async function confirmMilestone(
	db: BetterSQLite3Database<any>,
	milestoneId: string,
	confirmedModules: ConfirmModule[]
): Promise<{ data: ConfirmResultModule[] } | { error: ConfirmError }> {
	// 1. Validate milestone preconditions (outside transaction — read-only)
	const milestone = await db
		.select()
		.from(milestones)
		.where(eq(milestones.id, milestoneId))
		.get();

	if (!milestone) {
		return { error: { code: 'not_found', message: `Milestone ${milestoneId} not found` } };
	}

	if (milestone.status !== 'draft') {
		return {
			error: {
				code: 'bad_request',
				message: `Milestone status is '${milestone.status}', expected 'draft'`
			}
		};
	}

	if (!milestone.sourceMd) {
		return {
			error: {
				code: 'bad_request',
				message: 'Milestone has no source markdown'
			}
		};
	}

	// 2. Pre-generate all IDs (async — must happen before sync transaction)
	// We scan once for the current max, then increment in memory.
	const existingModules = await db
		.select({ id: modules.id })
		.from(modules)
		.where(eq(modules.milestoneId, milestoneId))
		.all();

	let maxModuleSeq = 0;
	for (const row of existingModules) {
		const parts = row.id.split('-');
		const seq = parseInt(parts[parts.length - 1], 10);
		if (seq > maxModuleSeq) maxModuleSeq = seq;
	}

	const existingTasks = await db.select({ id: tasks.id, shortId: tasks.shortId }).from(tasks).all();
	let maxTaskSeq = 0;
	let maxShortId = 0;
	for (const row of existingTasks) {
		const seq = parseInt(row.id.replace('TASK-', ''), 10);
		if (seq > maxTaskSeq) maxTaskSeq = seq;
		if (row.shortId > maxShortId) maxShortId = row.shortId;
	}

	// Build module entries with pre-computed IDs
	const moduleEntries: Array<{
		id: string;
		mod: ConfirmModule;
		index: number;
	}> = [];

	for (let i = 0; i < confirmedModules.length; i++) {
		maxModuleSeq++;
		moduleEntries.push({
			id: `MOD-${milestoneId.replace('MS-', '')}-${maxModuleSeq}`,
			mod: confirmedModules[i],
			index: i
		});
	}

	// Build task entries with pre-computed IDs
	const taskEntries: Array<{
		id: string;
		shortId: number;
		moduleIndex: number;
		taskIndex: number;
		title: string;
		description: string | null;
	}> = [];

	for (const entry of moduleEntries) {
		for (let t = 0; t < entry.mod.tasks.length; t++) {
			maxTaskSeq++;
			maxShortId++;
			taskEntries.push({
				id: `TASK-${maxTaskSeq}`,
				shortId: maxShortId,
				moduleIndex: entry.index,
				taskIndex: t,
				title: entry.mod.tasks[t].title,
				description: entry.mod.tasks[t].description ?? null
			});
		}
	}

	// 3. Atomic write in a synchronous transaction
	const createdModules = db.transaction((tx) => {
		const result: ConfirmResultModule[] = [];

		for (const entry of moduleEntries) {
			tx.insert(modules).values({
				id: entry.id,
				milestoneId,
				name: entry.mod.name,
				description: entry.mod.description ?? null,
				sortOrder: entry.index
			}).run();

			const modTasks = taskEntries
				.filter((te) => te.moduleIndex === entry.index)
				.map((te) => {
					tx.insert(tasks).values({
						id: te.id,
						shortId: te.shortId,
						moduleId: entry.id,
						title: te.title,
						description: te.description
					}).run();

					return {
						id: te.id,
						shortId: te.shortId,
						moduleId: entry.id,
						title: te.title,
						description: te.description,
						status: 'todo'
					};
				});

			result.push({
				id: entry.id,
				milestoneId,
				name: entry.mod.name,
				description: entry.mod.description ?? null,
				status: 'draft',
				sortOrder: entry.index,
				tasks: modTasks
			});
		}

		// Activate milestone
		tx.update(milestones)
			.set({ status: 'in-progress' })
			.where(eq(milestones.id, milestoneId))
			.run();

		return result;
	});

	const totalTasks = createdModules.reduce((sum, m) => sum + m.tasks.length, 0);
	logger.info('Milestone confirmed', {
		milestoneId,
		moduleCount: createdModules.length,
		taskCount: totalTasks
	});

	return { data: createdModules };
}

/**
 * Decompose service — orchestrates LLM-based milestone decomposition.
 *
 * 1. Reads the milestone's source markdown
 * 2. Sends it to the LLM with a structured system prompt
 * 3. Incrementally parses the streaming JSON array response
 * 4. Validates each module with Zod as it becomes available
 * 5. Yields SSE events (module / error / done)
 *
 * No data is written to the database — that's S03's responsibility.
 */

import { LlmClient } from './llm-client.js';
import { createLogger } from './logger.js';
import {
	decomposeModuleSchema,
	type DecomposeModule,
	type DecomposeEvent,
	type DecomposeModuleEvent,
	type DecomposeErrorEvent,
	type DecomposeDoneEvent
} from '$lib/schemas/decompose.js';

// ── System prompt ────────────────────────────────────────────────────────────

const logger = createLogger('decompose-service');

const SYSTEM_PROMPT = `你是一个专业的项目管理助手。你的任务是将需求文档拆解为结构化的模块和任务。

## 输出格式

你必须且只能输出一个 JSON 数组，不要包含任何其他文本、注释或 markdown 标记。

\`\`\`json
[
  {
    "name": "模块名称",
    "description": "模块的简要描述",
    "tasks": [
      {
        "title": "任务标题",
        "description": "任务的详细描述（可选）"
      }
    ]
  }
]
\`\`\`

## 拆解原则

1. 每个模块应该是内聚的、可独立开发和交付的功能单元
2. 每个任务应该是明确的、可验证的工作项
3. 模块之间应该有清晰的边界和最小依赖
4. 任务粒度适中：太大需要再拆分，太小则合并
5. 保持模块名称简洁（2-10 个字），描述清晰
6. 任务标题应该是动作导向的（如"实现XX功能"而非"XX功能"）
7. 按照逻辑依赖顺序排列模块

## 注意事项

- 只输出 JSON 数组，不要输出其他任何内容
- 如果需求文档不清晰，根据上下文做出合理推断
- 每个模块至少包含一个任务
- 确保所有任务合起来能覆盖需求文档的全部内容`;

// ── Incremental JSON object extractor ───────────────────────────────────────

/**
 * Tracks brace depth, string state, and escape state to extract
 * complete JSON objects from a streaming byte buffer.
 *
 * Handles:
 * - Nested objects and arrays
 * - Strings containing braces and brackets
 * - Escaped characters inside strings
 * - Multiple complete objects in one chunk
 * - Objects split across chunks
 */
export function extractCompleteJsonObjects(buffer: string): {
	objects: string[];
	remaining: string;
} {
	const objects: string[] = [];
	let depth = 0;
	let inString = false;
	let escaped = false;
	let objStart = -1;

	for (let i = 0; i < buffer.length; i++) {
		const ch = buffer[i];

		if (escaped) {
			escaped = false;
			continue;
		}

		if (ch === '\\' && inString) {
			escaped = true;
			continue;
		}

		if (ch === '"') {
			inString = !inString;
			continue;
		}

		if (inString) continue;

		if (ch === '{' || ch === '[') {
			if (depth === 0) {
				objStart = i;
			}
			depth++;
		} else if (ch === '}' || ch === ']') {
			depth--;
			if (depth === 0 && objStart !== -1) {
				objects.push(buffer.slice(objStart, i + 1));
				objStart = -1;
			}
		}
	}

	return {
		objects,
		remaining: objStart !== -1 ? buffer.slice(objStart) : ''
	};
}

// ── Public API ───────────────────────────────────────────────────────────────

/**
 * Stream-decompose a milestone's source markdown into modules via LLM.
 *
 * @param sourceMd - The raw markdown content of the milestone
 * @param client   - Optional LlmClient instance (for testing / custom config)
 *
 * Yields `DecomposeEvent` objects:
 * - `{ type: 'module', index, module }` — successfully validated module
 * - `{ type: 'error', stage, message }` — error during the process
 * - `{ type: 'done', total, errors }` — stream complete
 */
export async function* streamDecompose(
	sourceMd: string,
	client?: LlmClient
): AsyncGenerator<DecomposeEvent> {
	const llm = client ?? new LlmClient();
	let moduleIndex = 0;
	let errorCount = 0;
	let jsonBuffer = '';

	const userMessage = `请将以下需求文档拆解为模块和任务：\n\n${sourceMd}`;

	try {
		// Phase 1: Connecting
		for await (const chunk of llm.chatCompletionStream(SYSTEM_PROMPT, userMessage)) {
			jsonBuffer += chunk;

			// Try to extract complete objects from the buffer
			const { objects, remaining } = extractCompleteJsonObjects(jsonBuffer);
			jsonBuffer = remaining;

			for (const jsonStr of objects) {
				// The extracted JSON might be an array (the LLM wraps modules in [])
				let candidates: unknown[];
				try {
					const parsed = JSON.parse(jsonStr);
					candidates = Array.isArray(parsed) ? parsed : [parsed];
				} catch {
					// JSON parse failed — might be an array with some bad elements.
					// Strip outer array brackets and re-extract individual objects.
					let innerStr = jsonStr.trim();
					if (innerStr.startsWith('[') && innerStr.endsWith(']')) {
						innerStr = innerStr.slice(1, -1);
					}
					const inner = extractCompleteJsonObjects(innerStr);
					if (inner.objects.length > 0) {
						const parsed: unknown[] = [];
						for (const s of inner.objects) {
							try { parsed.push(JSON.parse(s)); } catch {
								errorCount++;
								yield { type: 'error', stage: 'parsing' as const, message: `JSON parse error: malformed object` };
							}
						}
						candidates = parsed;
						if (candidates.length === 0) continue;
					} else {
						// Truly unparseable
						errorCount++;
						const event: DecomposeErrorEvent = {
							type: 'error',
							stage: 'parsing',
							message: `JSON parse error: unparseable content`
						};
						yield event;
						logger.warn('JSON parse error: unparseable content');
						continue;
					}
				}

				for (const candidate of candidates) {
					const result = decomposeModuleSchema.safeParse(candidate);

					if (result.success) {
						const event: DecomposeModuleEvent = {
							type: 'module',
							index: moduleIndex++,
							module: result.data
						};
						yield event;
					} else {
						errorCount++;
						const detail = result.error.issues.map((i) => `${i.path.join('.')}: ${i.message}`).join('; ');
						const event: DecomposeErrorEvent = {
							type: 'error',
							stage: 'parsing',
							message: `Zod validation failed: ${detail}`
						};
						yield event;
						logger.warn('Zod validation failed for module', { detail });
					}
				}
			}
		}

		// Phase 2: Handle any remaining buffer (partial object at end of stream)
		if (jsonBuffer.trim()) {
			// Try wrapping in array brackets if it looks like the LLM forgot them
			let finalBuffer = jsonBuffer.trim();
			if (!finalBuffer.startsWith('[') && !finalBuffer.startsWith('{')) {
				finalBuffer = `[${finalBuffer}]`;
			}

			const { objects } = extractCompleteJsonObjects(finalBuffer);
			for (const jsonStr of objects) {
				let candidates: unknown[];
				try {
					const parsed = JSON.parse(jsonStr);
					candidates = Array.isArray(parsed) ? parsed : [parsed];
				} catch (parseErr: any) {
					errorCount++;
					const event: DecomposeErrorEvent = {
						type: 'error',
						stage: 'parsing',
						message: `JSON parse error on remaining buffer: ${parseErr.message}`
					};
					yield event;
					continue;
				}

				for (const candidate of candidates) {
					const result = decomposeModuleSchema.safeParse(candidate);
					if (result.success) {
						const event: DecomposeModuleEvent = {
							type: 'module',
							index: moduleIndex++,
							module: result.data
						};
						yield event;
					} else {
						errorCount++;
						const detail = result.error.issues.map((i) => `${i.path.join('.')}: ${i.message}`).join('; ');
						const event: DecomposeErrorEvent = {
							type: 'error',
							stage: 'parsing',
							message: `Zod validation failed: ${detail}`
						};
						yield event;
					}
				}
			}
		}
	} catch (err: any) {
		errorCount++;
		// Classify the error stage
		let stage: 'connecting' | 'streaming' | 'parsing' = 'connecting';
		if (moduleIndex > 0) {
			stage = 'streaming';
		}
		const event: DecomposeErrorEvent = {
			type: 'error',
			stage,
			message: err.message
		};
		yield event;
		logger.warn('Stream error', { error: err.message });
	} finally {
		const doneEvent: DecomposeDoneEvent = {
			type: 'done',
			total: moduleIndex,
			errors: errorCount
		};
		yield doneEvent;
		logger.info('Stream complete', { total: moduleIndex, errors: errorCount });
	}
}

import { redirect, json } from '@sveltejs/kit';
import type { Handle } from '@sveltejs/kit';
import { checkAuth } from '$lib/server/auth.js';
import { createLogger } from '$lib/server/logger.js';

const logger = createLogger('request');

/** Paths to skip from request logging (static assets, health checks). */
const SKIP_LOG_PATHS = ['/_app/', '/favicon', '/api/health'];

export const handle: Handle = async ({ event, resolve }) => {
	const { url, request, cookies } = event;
	const path = url.pathname;

	// Skip auth for static assets and prerendered pages
	if (path.startsWith('/_app/') || path.startsWith('/favicon')) {
		return resolve(event);
	}

	// Skip request logging for health checks and static assets
	const shouldLog = !SKIP_LOG_PATHS.some((p) => path === p || path.startsWith(p));

	// Measure request duration
	const start = performance.now();

	// Log incoming request
	if (shouldLog) {
		const userAgent = request.headers.get('user-agent') ?? 'unknown';
		logger.info('Incoming request', { method: request.method, path, userAgent });
	}

	// Public routes — no auth required
	const publicRoutes = ['/login', '/api/auth/login', '/api/auth/logout', '/api/health'];
	if (publicRoutes.some((r) => path === r || path.startsWith(r + '/'))) {
		// If already authenticated and visiting /login, redirect to home
		if (path === '/login') {
			const cookieHeader = request.headers.get('cookie');
			const authHeader = request.headers.get('authorization');
			const result = checkAuth(cookieHeader, authHeader);
			if (result.authenticated) {
				throw redirect(302, '/');
			}
		}
		return logResponse(resolve(event), start, request.method, path, shouldLog);
	}

	// ── API routes: require auth (cookie or bearer) ──
	if (path.startsWith('/api/')) {
		const cookieHeader = request.headers.get('cookie');
		const authHeader = request.headers.get('authorization');
		const result = checkAuth(cookieHeader, authHeader);

		if (!result.authenticated) {
			// Return 401 JSON for API routes
			const response = json(
				{
					error: 'unauthorized',
					message: result.reason === 'invalid_bearer_token' ? '无效的 API Key' : '请先登录'
				},
				{ status: 401 }
			);
			return logResponse(Promise.resolve(response), start, request.method, path, shouldLog);
		}

		// Attach auth method to locals for downstream use
		event.locals.authMethod = result.method;
		return logResponse(resolve(event), start, request.method, path, shouldLog);
	}

	// ── Page routes: require cookie auth, redirect to /login ──
	const cookieHeader = request.headers.get('cookie');
	const authHeader = request.headers.get('authorization');
	const result = checkAuth(cookieHeader, authHeader);

	if (!result.authenticated) {
		throw redirect(302, '/login');
	}

	event.locals.authMethod = result.method;
	return logResponse(resolve(event), start, request.method, path, shouldLog);
};

/** Wrap response promise with duration logging. */
function logResponse(
	responsePromise: Response | Promise<Response>,
	start: number,
	method: string,
	path: string,
	shouldLog: boolean
): Response | Promise<Response> {
	if (!shouldLog) return responsePromise;

	return Promise.resolve(responsePromise).then((response) => {
		const durationMs = Math.round(performance.now() - start);
		logger.info('Request completed', { method, path, status: response.status, durationMs });
		return response;
	});
}

/**
 * Structured logger — zero external dependencies.
 *
 * Factory: `createLogger(module)` returns { debug, info, warn, error }.
 *
 * Format: `[ISO_TIMESTAMP] [LEVEL] [module] message {meta JSON}`
 * Output: stdout (level-appropriate stream) + append to logs/app-YYYY-MM-DD.log
 * Control: LOG_LEVEL env var (default 'info'). Values: debug, info, warn, error.
 * Rotation: on each write, check date rollover; on startup, prune files older than 7 days.
 * Graceful degradation: file write failure → warning to stdout, continue stdout-only.
 * Secret redaction: never log values matching common secret patterns.
 */

import { existsSync, mkdirSync, appendFileSync, readdirSync, unlinkSync, statSync } from 'node:fs';
import { join } from 'node:path';

// ── Types ────────────────────────────────────────────────────────────────────

export type LogLevel = 'debug' | 'info' | 'warn' | 'error';

export interface Logger {
	debug: (message: string, meta?: Record<string, unknown>) => void;
	info: (message: string, meta?: Record<string, unknown>) => void;
	warn: (message: string, meta?: Record<string, unknown>) => void;
	error: (message: string, meta?: Record<string, unknown>) => void;
}

export interface LoggerOptions {
	/** Minimum log level. Overrides LOG_LEVEL env var when provided. */
	level?: LogLevel;
	/** Directory for log files. Default: 'logs' relative to cwd. */
	logDir?: string;
	/** Maximum age of log files in days before auto-deletion. Default: 7. */
	maxAgeDays?: number;
}

// ── Constants ────────────────────────────────────────────────────────────────

const LEVEL_PRIORITY: Record<LogLevel, number> = {
	debug: 0,
	info: 1,
	warn: 2,
	error: 3
};

const LEVEL_TAG: Record<LogLevel, string> = {
	debug: 'DEBUG',
	info: 'INFO',
	warn: 'WARN',
	error: 'ERROR'
};

const CONSOLE_FN: Record<LogLevel, 'debug' | 'info' | 'warn' | 'error'> = {
	debug: 'debug',
	info: 'info',
	warn: 'warn',
	error: 'error'
};

const DEFAULT_LOG_DIR = 'logs';
const DEFAULT_MAX_AGE_DAYS = 7;

/** Patterns that indicate secret values — matched against stringified meta values. */
const SECRET_PATTERNS = [
	/api[_-]?key/i,
	/password/i,
	/bearer\s+\S+/i,
	/secret/i,
	/authorization/i,
	/token(?!\s*:?\s*null)/i
];

// ── Helpers ──────────────────────────────────────────────────────────────────

function resolveLevel(): LogLevel {
	const env = (process.env.LOG_LEVEL ?? 'info').toLowerCase().trim();
	if (env in LEVEL_PRIORITY) return env as LogLevel;
	return 'info';
}

function todayDateStr(): string {
	return new Date().toISOString().slice(0, 10); // YYYY-MM-DD
}

function isoTimestamp(): string {
	return new Date().toISOString();
}

/**
 * Redact secret values from a meta object.
 * Returns a new object with sensitive values replaced by '[REDACTED]'.
 */
function redactMeta(meta: Record<string, unknown>): Record<string, unknown> {
	const result: Record<string, unknown> = {};
	for (const [key, value] of Object.entries(meta)) {
		if (SECRET_PATTERNS.some((pat) => pat.test(key))) {
			result[key] = '[REDACTED]';
		} else if (typeof value === 'string' && SECRET_PATTERNS.some((pat) => pat.test(value))) {
			result[key] = '[REDACTED]';
		} else {
			result[key] = value;
		}
	}
	return result;
}

function formatLine(level: LogLevel, mod: string, message: string, meta?: Record<string, unknown>): string {
	const ts = isoTimestamp();
	const tag = LEVEL_TAG[level];
	const metaStr = meta ? ` ${JSON.stringify(redactMeta(meta))}` : '';
	return `[${ts}] [${tag}] [${mod}] ${message}${metaStr}\n`;
}

// ── File operations ──────────────────────────────────────────────────────────

/** Ensure the log directory exists; return its path. */
function ensureLogDir(logDir: string): string | null {
	try {
		if (!existsSync(logDir)) {
			mkdirSync(logDir, { recursive: true });
		}
		return logDir;
	} catch {
		return null;
	}
}

/** Append a line to the daily log file. Graceful degradation on failure. */
function appendToLogFile(logDir: string, content: string): void {
	try {
		const dateStr = todayDateStr();
		const filePath = join(logDir, `app-${dateStr}.log`);
		appendFileSync(filePath, content, 'utf-8');
	} catch {
		// Intentionally swallowed — stdout-only degradation
	}
}

/**
 * Delete log files older than maxAgeDays.
 * Runs once on startup; errors for individual files are swallowed.
 */
export function pruneOldLogs(logDir: string, maxAgeDays: number): void {
	if (!existsSync(logDir)) return;

	const now = Date.now();
	const maxAgeMs = maxAgeDays * 24 * 60 * 60 * 1000;

	try {
		const files = readdirSync(logDir);
		for (const file of files) {
			if (!file.startsWith('app-') || !file.endsWith('.log')) continue;
			const filePath = join(logDir, file);
			try {
				const stat = statSync(filePath);
				if (now - stat.mtimeMs > maxAgeMs) {
					unlinkSync(filePath);
				}
			} catch {
				// Skip files we can't stat/delete
			}
		}
	} catch {
		// Skip if we can't read directory
	}
}

// ── Singleton state ─────────────────────────────────────────────────────────

let initialized = false;
let effectiveLogDir: string | null = null;

function initialize(logDir: string, maxAgeDays: number): void {
	if (initialized) return;
	initialized = true;
	effectiveLogDir = ensureLogDir(logDir);
	if (effectiveLogDir) {
		pruneOldLogs(effectiveLogDir, maxAgeDays);
	}
}

// ── Factory ──────────────────────────────────────────────────────────────────

/**
 * Create a structured logger for the given module name.
 *
 * @example
 * ```ts
 * const log = createLogger('my-module');
 * log.info('Server started', { port: 3000 });
 * ```
 */
export function createLogger(mod: string, opts?: LoggerOptions): Logger {
	const minLevel = opts?.level ?? resolveLevel();
	const minPriority = LEVEL_PRIORITY[minLevel];
	const logDir = opts?.logDir ?? DEFAULT_LOG_DIR;
	const maxAgeDays = opts?.maxAgeDays ?? DEFAULT_MAX_AGE_DAYS;

	// Initialize once (prune old logs, ensure directory)
	initialize(logDir, maxAgeDays);

	return {
		debug: (message: string, meta?: Record<string, unknown>) => {
			if (minPriority > LEVEL_PRIORITY.debug) return;
			const line = formatLine('debug', mod, message, meta);
			console.debug(line.trimEnd());
			if (effectiveLogDir) appendToLogFile(effectiveLogDir, line);
		},
		info: (message: string, meta?: Record<string, unknown>) => {
			if (minPriority > LEVEL_PRIORITY.info) return;
			const line = formatLine('info', mod, message, meta);
			console.info(line.trimEnd());
			if (effectiveLogDir) appendToLogFile(effectiveLogDir, line);
		},
		warn: (message: string, meta?: Record<string, unknown>) => {
			if (minPriority > LEVEL_PRIORITY.warn) return;
			const line = formatLine('warn', mod, message, meta);
			console.warn(line.trimEnd());
			if (effectiveLogDir) appendToLogFile(effectiveLogDir, line);
		},
		error: (message: string, meta?: Record<string, unknown>) => {
			if (minPriority > LEVEL_PRIORITY.error) return;
			const line = formatLine('error', mod, message, meta);
			console.error(line.trimEnd());
			if (effectiveLogDir) appendToLogFile(effectiveLogDir, line);
		}
	};
}

// ── Test helpers (exported for testing only) ─────────────────────────────────

/**
 * Reset the singleton initialization state.
 * Only intended for use in tests.
 */
export function _resetLoggerState(): void {
	initialized = false;
	effectiveLogDir = null;
}

